    /// <param name="e">
    /// Аргументы, связанные с событием.
    /// </param>
    private void ParentDirectoryIdChanged(object? sender, EventArgs e)
    {
        //  Блокировка критического объекта.
        lock (_ParentDirectorySync)
        {
            //  Проверка ссылки на сущность.
            if (_ParentDirectory is not null)
            {
                //  Установка нового идентификатора.
                ParentDirectoryId = _ParentDirectory.Id;
            }
        }
    }
    
    /// <summary>
