        typeBuilder.Property(internalDirectory => internalDirectory.Name);
        typeBuilder.HasIndex(internalDirectory => internalDirectory.Name);
        
        //  Настройка свойства "Относительный путь к каталогу".
        typeBuilder.Property(internalDirectory => internalDirectory.Path);
        typeBuilder.HasIndex(internalDirectory => internalDirectory.Path);
        
        //  Настройка идентификатора свойства "Файловое хранилище".
        typeBuilder.Property(internalDirectory => internalDirectory.FileStorageId);
        typeBuilder.HasIndex(internalDirectory => internalDirectory.FileStorageId);
        
        //  Настройка свойства "Файловое хранилище".
        typeBuilder.HasOne(internalDirectory => internalDirectory.FileStorage)
