            .HasForeignKey(internalDirectory => internalDirectory.FileStorageId)
            .OnDelete(DeleteBehavior.NoAction)
            .HasConstraintName("FK_InternalDirectories_FileStorages");
        
        //  Настройка идентификатора свойства "Общий каталог".
        typeBuilder.Property(internalDirectory => internalDirectory.GeneralDirectoryId);
        typeBuilder.HasIndex(internalDirectory => internalDirectory.GeneralDirectoryId);
        
        //  Настройка свойства "Общий каталог".
