        //  Настройка идентификатора свойства "Родительский каталог".
        typeBuilder.Property(internalDirectory => internalDirectory.ParentDirectoryId);
        typeBuilder.HasIndex(internalDirectory => internalDirectory.ParentDirectoryId);
        
